</head>
<body>

  <div class="container">
    <header>
      <h1>SANDBOX AUTOMATA</h1>
      <p class="subtitle">Interactive Falling-Sand Simulator</p>
    </header>

    <div class="canvas-wrapper">
      <canvas id="sand"></canvas>
    </div>

    <div class="toolbar">
      <div class="btn-group">
        <button id="mat-sand" class="mat-btn active"><span class="dot dot-sand"></span>SAND</button>
        <button id="mat-water" class="mat-btn"><span class="dot dot-water"></span>WATER</button>
        <button id="mat-wall" class="mat-btn"><span class="dot dot-wall"></span>WALL</button>
        <button id="mat-acid" class="mat-btn"><span class="dot dot-acid"></span>ACID</button>
        <button id="mat-empty" class="mat-btn"><span class="dot dot-empty"></span>ERASER</button>
        <button id="clear">CLEAR</button>
      </div>

      <div class="sub-toolbar">
        <div class="brush-controls">
          <span>Brush Size:</span>
          <button class="brush-btn" data-radius="1">S</button>
          <button class="brush-btn active" data-radius="2">M</button>
          <button class="brush-btn" data-radius="4">L</button>
        </div>
        <button id="pause-btn" class="brush-btn">PAUSE</button>
      </div>
    </div>
  </div>

  <script>
    (function () {
      const W = 100;
      const H = 100;

      // Element Types
      const EMPTY = 0;
      const SAND = 1;
      const WATER = 2;
      const WALL = 3;
      const ACID = 4;

      const MAT_NAMES = ["empty", "sand", "water", "wall", "acid"];
      const MAT_IDS = { empty: 0, sand: 1, water: 2, wall: 3, acid: 4 };

      const grid = new Uint8Array(W * H);
      const updated = new Uint8Array(W * H);

      let currentMaterial = "sand";
      let brushRadius = 2;
      let isPaused = false;

      // Canvas setup
      const canvas = document.getElementById("sand");
      const ctx = canvas.getContext("2d");
      canvas.width = W;
      canvas.height = H;

      const imgData = ctx.createImageData(W, H);
      const pixels = imgData.data;

      // Render grid onto canvas ImageData
      function render() {
        let p = 0;
        for (let i = 0; i < W * H; i++) {
          const type = grid[i];
          if (type === EMPTY) {
            pixels[p]     = 18;
            pixels[p + 1] = 18;
            pixels[p + 2] = 30;
            pixels[p + 3] = 255;
          } else if (type === SAND) {
            const noise = (i * 13) % 20 - 10;
            pixels[p]     = Math.min(255, Math.max(0, 245 + noise));
            pixels[p + 1] = Math.min(255, Math.max(0, 190 + noise));
            pixels[p + 2] = Math.min(255, Math.max(0, 35 + noise));
            pixels[p + 3] = 255;
          } else if (type === WATER) {
            const noise = (i * 7) % 20 - 10;
            pixels[p]     = Math.min(255, Math.max(0, 50 + noise));
            pixels[p + 1] = Math.min(255, Math.max(0, 160 + noise));
            pixels[p + 2] = Math.min(255, Math.max(0, 240 + noise));
            pixels[p + 3] = 220;
          } else if (type === WALL) {
            pixels[p]     = 130;
            pixels[p + 1] = 140;
            pixels[p + 2] = 150;
            pixels[p + 3] = 255;
          } else if (type === ACID) {
            const noise = (i * 11) % 20 - 10;
            pixels[p]     = Math.min(255, Math.max(0, 50 + noise));
            pixels[p + 1] = Math.min(255, Math.max(0, 240 + noise));
            pixels[p + 2] = Math.min(255, Math.max(0, 90 + noise));
            pixels[p + 3] = 230;
          }
          p += 4;
        }
        ctx.putImageData(imgData, 0, 0);
      }

      // Helper to handle liquid displacement when sand enters a liquid cell
      function sinkSand(sx, sy, tx, ty, liquidType) {
        const candidateCoords = [
          [tx - 1, ty],
          [tx + 1, ty],
          [tx - 1, ty - 1],
          [tx + 1, ty - 1],
          [sx - 1, sy],
          [sx + 1, sy]
        ];

        // Shuffle candidate positions
        for (let i = candidateCoords.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          const tmp = candidateCoords[i];
          candidateCoords[i] = candidateCoords[j];
          candidateCoords[j] = tmp;
        }

        let displacedIdx = null;
        for (let k = 0; k < candidateCoords.length; k++) {
          const cx = candidateCoords[k][0];
          const cy = candidateCoords[k][1];
          if (cx >= 0 && cx < W && cy >= 0 && cy < H) {
            const cIdx = cy * W + cx;
            if (grid[cIdx] === EMPTY) {
              displacedIdx = cIdx;
              break;
            }
          }
        }

        const sIdx = sy * W + sx;
        const tIdx = ty * W + tx;

        if (displacedIdx !== null) {
          // Displace liquid sideways/locally into empty air
          grid[displacedIdx] = liquidType;
          updated[displacedIdx] = 1;

          grid[tIdx] = SAND;
          updated[tIdx] = 1;

          grid[sIdx] = EMPTY;
        } else {
          // Direct swap if fully enclosed
          grid[tIdx] = SAND;
          grid[sIdx] = liquidType;
          updated[tIdx] = 1;
          updated[sIdx] = 1;
        }
      }

      // Single step simulation update (bottom-row up)
      function simStep() {
        updated.fill(0);

        for (let y = H - 1; y >= 0; y--) {
          const leftToRight = Math.random() < 0.5;
          const startX = leftToRight ? 0 : W - 1;
          const endX = leftToRight ? W : -1;
          const stepX = leftToRight ? 1 : -1;

          for (let x = startX; x !== endX; x += stepX) {
            const idx = y * W + x;
            if (updated[idx]) continue;

            const type = grid[idx];
            if (type === EMPTY || type === WALL) continue;

            if (type === SAND) {
              const ny = y + 1;
              if (ny < H) {
                const downIdx = ny * W + x;
                const downType = grid[downIdx];

                if (downType === EMPTY) {
                  grid[idx] = EMPTY;
                  grid[downIdx] = SAND;
                  updated[downIdx] = 1;
                  continue;
                } else if (downType === WATER || downType === ACID) {
                  sinkSand(x, y, x, ny, downType);
                  continue;
                }
              }

              // Diagonal sliding
              const dir = Math.random() < 0.5 ? -1 : 1;
              const dirs = [dir, -dir];
              let moved = false;

              for (let i = 0; i < 2; i++) {
                const d = dirs[i];
                const nx = x + d;
                const ny = y + 1;
                if (nx >= 0 && nx < W && ny < H) {
                  const diagIdx = ny * W + nx;
                  const diagType = grid[diagIdx];

                  if (diagType === EMPTY) {
                    grid[idx] = EMPTY;
                    grid[diagIdx] = SAND;
                    updated[diagIdx] = 1;
                    moved = true;
                    break;
                  } else if (diagType === WATER || diagType === ACID) {
                    sinkSand(x, y, nx, ny, diagType);
                    moved = true;
                    break;
                  }
                }
              }
              if (moved) continue;

            } else if (type === WATER) {
              const ny = y + 1;

              // 1. Straight down
              if (ny < H && grid[ny * W + x] === EMPTY) {
                grid[idx] = EMPTY;
                grid[ny * W + x] = WATER;
                updated[ny * W + x] = 1;
                continue;
              }

              const dir = Math.random() < 0.5 ? -1 : 1;
              const dirs = [dir, -dir];
              let moved = false;

              // 2. Diagonal down
              for (let i = 0; i < 2; i++) {
                const d = dirs[i];
                const nx = x + d;
                if (nx >= 0 && nx < W && ny < H && grid[ny * W + nx] === EMPTY) {
                  grid[idx] = EMPTY;
                  grid[ny * W + nx] = WATER;
                  updated[ny * W + nx] = 1;
                  moved = true;
                  break;
                }
              }
              if (moved) continue;

              // 3. Horizontal spread
              for (let i = 0; i < 2; i++) {
                const d = dirs[i];
                const nx = x + d;
                if (nx >= 0 && nx < W && grid[y * W + nx] === EMPTY) {
                  grid[idx] = EMPTY;
                  grid[y * W + nx] = WATER;
                  updated[y * W + nx] = 1;
                  moved = true;
                  break;
                }
              }
              if (moved) continue;

            } else if (type === ACID) {
              let dissolved = false;

              // Dissolve below first
              if (y + 1 < H) {
                const targetIdx = (y + 1) * W + x;
                const targetType = grid[targetIdx];
                if (targetType === SAND || targetType === WALL) {
                  grid[idx] = EMPTY;
                  grid[targetIdx] = EMPTY;
                  updated[targetIdx] = 1;
                  dissolved = true;
                }
              }

              // Dissolve beside
              if (!dissolved) {
                const dir = Math.random() < 0.5 ? -1 : 1;
                const dirs = [dir, -dir];
                for (let i = 0; i < 2; i++) {
                  const d = dirs[i];
                  const nx = x + d;
                  if (nx >= 0 && nx < W) {
                    const targetIdx = y * W + nx;
                    const targetType = grid[targetIdx];
                    if (targetType === SAND || targetType === WALL) {
                      grid[idx] = EMPTY;
                      grid[targetIdx] = EMPTY;
                      updated[targetIdx] = 1;
                      dissolved = true;
                      break;
                    }
                  }
                }
              }

              if (dissolved) continue;

              // Move like water
              const ny = y + 1;
              if (ny < H && grid[ny * W + x] === EMPTY) {
                grid[idx] = EMPTY;
                grid[ny * W + x] = ACID;
                updated[ny * W + x] = 1;
                continue;
              }

              const dir = Math.random() < 0.5 ? -1 : 1;
              const dirs = [dir, -dir];
              let moved = false;

              for (let i = 0; i < 2; i++) {
                const d = dirs[i];
                const nx = x + d;
                if (nx >= 0 && nx < W && ny < H && grid[ny * W + nx] === EMPTY) {
                  grid[idx] = EMPTY;
                  grid[ny * W + nx] = ACID;
                  updated[ny * W + nx] = 1;
                  moved = true;
                  break;
                }
              }
              if (moved) continue;

              for (let i = 0; i < 2; i++) {
                const d = dirs[i];
                const nx = x + d;
                if (nx >= 0 && nx < W && grid[y * W + nx] === EMPTY) {
                  grid[idx] = EMPTY;
                  grid[y * W + nx] = ACID;
                  updated[y * W + nx] = 1;
                  moved = true;
                  break;
                }
              }
              if (moved) continue;
            }
          }
        }
      }

      // Required Public API on window.sim
      window.sim = {
        w: W,
        h: H,
        tick(n) {
          const steps = (typeof n === 'number' && n > 0) ? Math.floor(n) : 1;
          for (let i = 0; i < steps; i++) {
            simStep();
          }
          render();
        },
        get(x, y) {
          if (x < 0 || x >= W || y < 0 || y >= H) return "empty";
          return MAT_NAMES[grid[y * W + x]] || "empty";
        },
        set(x, y, material) {
          if (x < 0 || x >= W || y < 0 || y >= H) return;
          const id = MAT_IDS[material];
          if (id !== undefined) {
            grid[y * W + x] = id;
            render();
          }
        },
        clear() {
          grid.fill(EMPTY);
          render();
        }
      };

      // User Painting Handlers
      let isMouseDown = false;
      let lastX = -1;
      let lastY = -1;

      function getCanvasCoords(e) {
        const rect = canvas.getBoundingClientRect();
        const clientX = e.touches ? e.touches[0].clientX : e.clientX;
        const clientY = e.touches ? e.touches[0].clientY : e.clientY;
        const x = Math.floor(((clientX - rect.left) / rect.width) * W);
        const y = Math.floor(((clientY - rect.top) / rect.height) * H);
        return {
          x: Math.max(0, Math.min(W - 1, x)),
          y: Math.max(0, Math.min(H - 1, y))
        };
      }

      function drawAt(gx, gy) {
        const r = brushRadius;
        const matId = MAT_IDS[currentMaterial];
        for (let dy = -r + 1; dy < r; dy++) {
          for (let dx = -r + 1; dx < r; dx++) {
            if (dx * dx + dy * dy <= r * r) {
              const nx = gx + dx;
              const ny = gy + dy;
              if (nx >= 0 && nx < W && ny >= 0 && ny < H) {
                grid[ny * W + nx] = matId;
              }
            }
          }
        }
        render();
      }

      function drawLine(x0, y0, x1, y1) {
        const dx = Math.abs(x1 - x0);
        const dy = Math.abs(y1 - y0);
        const sx = x0 < x1 ? 1 : -1;
        const sy = y0 < y1 ? 1 : -1;
        let err = dx - dy;

        let currX = x0;
        let currY = y0;

        while (true) {
          drawAt(currX, currY);
          if (currX === x1 && currY === y1) break;
          const e2 = 2 * err;
          if (e2 > -dy) { err -= dy; currX += sx; }
          if (e2 < dx) { err += dx; currY += sy; }
        }
      }

      canvas.addEventListener("mousedown", (e) => {
        isMouseDown = true;
        const coords = getCanvasCoords(e);
        lastX = coords.x;
        lastY = coords.y;
        drawAt(coords.x, coords.y);
      });

      window.addEventListener("mousemove", (e) => {
        if (!isMouseDown) return;
        const coords = getCanvasCoords(e);
        drawLine(lastX, lastY, coords.x, coords.y);
        lastX = coords.x;
        lastY = coords.y;
      });

      window.addEventListener("mouseup", () => { isMouseDown = false; });

      canvas.addEventListener("touchstart", (e) => {
        e.preventDefault();
        isMouseDown = true;
        const coords = getCanvasCoords(e);
        lastX = coords.x;
        lastY = coords.y;
        drawAt(coords.x, coords.y);
      }, { passive: false });

      canvas.addEventListener("touchmove", (e) => {
        e.preventDefault();
        if (!isMouseDown) return;
        const coords = getCanvasCoords(e);
        drawLine(lastX, lastY, coords.x, coords.y);
        lastX = coords.x;
        lastY = coords.y;
      }, { passive: false });

      window.addEventListener("touchend", () => { isMouseDown = false; });

      // UI Controls setup
      const matButtons = {
        "mat-sand": "sand",
        "mat-water": "water",
        "mat-wall": "wall",
        "mat-acid": "acid",
        "mat-empty": "empty"
      };

      Object.entries(matButtons).forEach(([id, matName]) => {
        const btn = document.getElementById(id);
        if (btn) {
          btn.addEventListener("click", () => {
            currentMaterial = matName;
            document.querySelectorAll(".mat-btn").forEach(b => b.classList.remove("active"));
            btn.classList.add("active");
          });
        }
      });

      const clearBtn = document.getElementById("clear");
      if (clearBtn) {
        clearBtn.addEventListener("click", () => {
          window.sim.clear();
        });
      }

      // Brush Radius Selectors
      document.querySelectorAll(".brush-btn[data-radius]").forEach(btn => {
        btn.addEventListener("click", () => {
          document.querySelectorAll(".brush-btn[data-radius]").forEach(b => b.classList.remove("active"));
          btn.classList.add("active");
          brushRadius = parseInt(btn.getAttribute("data-radius"), 10);
        });
      });

      // Pause/Play Toggle
      const pauseBtn = document.getElementById("pause-btn");
      if (pauseBtn) {
        pauseBtn.addEventListener("click", () => {
          isPaused = !isPaused;
          pauseBtn.textContent = isPaused ? "PLAY" : "PAUSE";
          pauseBtn.classList.toggle("active", isPaused);
        });
      }

      // Animation Loop
      function animationLoop() {
        if (!isPaused) {
          simStep();
          render();
        }
        requestAnimationFrame(animationLoop);
      }

      // Initial Render and Start
      render();
      requestAnimationFrame(animationLoop);
    })();
  </script>
</body>
</html>
